		((Control)MySkinsTabButton).StyleClasses.Remove("ButtonColorGreen");
		((Control)ShopTabButton).StyleClasses.Remove("ButtonColorGreen");
		((Control)EmotesTabButton).StyleClasses.Remove("ButtonColorGreen");
		switch (tabName)
		{
		case "skins":
			((Control)MySkinsTabButton).StyleClasses.Add("ButtonColorGreen");
			ShowCategory(_currentCategory);
			break;
		case "shop":
			((Control)ShopTabButton).StyleClasses.Add("ButtonColorGreen");
			ShowShop();
			break;
		case "emotes":
			((Control)EmotesTabButton).StyleClasses.Add("ButtonColorGreen");
			ShowEmotes();
			break;
		}
	}

