	private bool IsValidShopOffer(SkinShopOfferInfo offer)
	{
		if (offer.Price <= 0)
		{
			return false;
		}
		if (!(offer.Currency == "coins"))
		{
			return offer.Currency == "premium";
		}
		return true;
	}

	private int GetLowestOfferPrice(SkinShopItemInfo shopItem)
	{
		return (from offer in shopItem.Offers.Where(IsValidShopOffer)
			select offer.Price).DefaultIfEmpty(int.MaxValue).Min();
	}

